static inline CredoSlice_t* get_slice(lua_State *L, int arg) {
    CredoSlice_t* slice = NULL;
    lua_pushstring(L, CR_REGISTRY_CMD_SLICES_MAP);
    lua_gettable(L, LUA_REGISTRYINDEX);
    lua_pushvalue(L, arg);
    lua_gettable(L, -2);
    slice = (CredoSlice_t*)lua_touserdata(L, -1);
    lua_pop(L, 2); // remove userdata
    return slice;

}
static inline CredoSlice_t* get_slice_handle(lua_State *L, int arg, bool* is_command) {
    CredoSlice_t* slice = NULL;
    lua_pushliteral(L, "credo_in_shell");
    lua_gettable(L, LUA_REGISTRYINDEX);
    bool in_shell = lua_toboolean(L, -1);
    *is_command = !in_shell;
    lua_pop(L, 1);
    lua_pushstring(L, CR_REGISTRY_CMD_SLICES_MAP);
    lua_gettable(L, LUA_REGISTRYINDEX);
    lua_pushvalue(L, arg);
    lua_gettable(L, -2);
    slice = (CredoSlice_t*)lua_touserdata(L, -1);
    lua_pop(L, 2); // remove userdata
    if (in_shell && slice != NULL) {
         slice->in_shell = true;
    }
    return slice;
}




typedef CredoError_t CredoErrorCheck_t;

static const char* errorcode_to_string(CredoError_t err) {
    switch (err) {
        case CR_OK:
            return "SUCCESS";
        case CR_FAIL:
            return "FAIL";
        case CR_PHY_FW_DOWNLOAD_FAIL:
            return "FW_DOWNLOAD_FAIL";
        case CR_FW_TIMEOUT:
            return "FW_TIMEOUT";
        case CR_NOT_READY:
            return "NOT_READY";
        case CR_OUT_OF_MEMORY:
            return "OUT_OF_MEMORY";
        case CR_HAL_LOAD_FAIL:
            return "HAL_LOAD_FAIL";
        case CR_HAL_NOT_FOUND:
            return "HAL_NOT_FOUND";
        case CR_INVALID_ARGS:
            return "INVALID_ARGS";
        case CR_MUTEX_TIMEOUT:
            return "MUTEX_TIMEOUT";
        case CR_UNSUPPORTED:
            return "UNSUPPORTED";
        case CR_NOTIMPLEMENTED:
            return "NOTIMPLEMENTED";
        default:
            return "UNKNOWN";
    }
}


